
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Bus, LogIn, Loader2 } from "lucide-react";
import Link from 'next/link';

type UserRole = 'admin' | 'driver' | 'parent';

const demoUsers = {
    admin: { email: 'admin@yellowtransit.com', password: 'password123' },
    driver: { email: 'driver@yellowtransit.com', password: 'password123' },
    parent: { email: 'parent@yellowtransit.com', password: 'password123' },
};

export default function LoginPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<UserRole>('admin');

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate API call
    setTimeout(() => {
        const demoUser = demoUsers[activeTab];
        if (email === demoUser.email && password === demoUser.password) {
            toast({
                title: "Login Successful",
                description: `Welcome! Redirecting to the ${activeTab} dashboard.`,
            });
            router.push(`/dashboard/${activeTab}`);
        } else {
            toast({
                variant: "destructive",
                title: "Login Failed",
                description: "Invalid email or password. Please try again.",
            });
            setIsLoading(false);
        }
    }, 1000);
  };
  
  const handleTabChange = (value: string) => {
      setActiveTab(value as UserRole);
      setEmail('');
      setPassword('');
  }

  return (
    <div className="flex min-h-screen flex-col items-center justify-center bg-muted/40 p-4">
      <div className="absolute top-4 left-4 z-10 hidden md:flex">
        <div className="flex items-center justify-center gap-2">
            <Bus className="h-6 w-6 text-primary" />
            <span className="text-lg font-semibold font-headline">SafeRoute</span>
        </div>
      </div>

      <Card className="w-full max-w-sm z-10">
          <CardHeader className="text-center">
              <div className="mx-auto bg-primary/20 text-primary p-3 rounded-full w-fit mb-4">
                  <Bus className="h-8 w-8" />
              </div>
              <CardTitle className="text-2xl font-bold font-headline">Welcome to SafeRoute</CardTitle>
              <CardDescription>Sign in to your account.</CardDescription>
          </CardHeader>
          <CardContent>
             <div className="flex justify-around mb-6 border-b">
                 <button onClick={() => handleTabChange('admin')} className={`py-2 px-4 text-sm font-medium ${activeTab === 'admin' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}>Admin</button>
                 <button onClick={() => handleTabChange('driver')} className={`py-2 px-4 text-sm font-medium ${activeTab === 'driver' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}>Driver</button>
                 <button onClick={() => handleTabChange('parent')} className={`py-2 px-4 text-sm font-medium ${activeTab === 'parent' ? 'border-b-2 border-primary text-primary' : 'text-muted-foreground'}`}>Parent</button>
            </div>
            <form onSubmit={handleLogin} className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="email">Email</Label>
                <Input 
                  id="email" 
                  type="email" 
                  placeholder="m@example.com" 
                  required 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  disabled={isLoading}
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label htmlFor="password">Password</Label>
                  <Link
                      href="#"
                      className="text-sm font-medium text-primary hover:underline"
                  >
                      Forgot password?
                  </Link>
                </div>
                <Input 
                  id="password" 
                  type="password" 
                  required 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  disabled={isLoading} 
                />
              </div>
              <Button type="submit" className="w-full" disabled={isLoading}>
                {isLoading ? (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                ) : (
                  <LogIn className="mr-2 h-4 w-4" />
                )}
                {isLoading ? 'Signing In...' : 'Sign In'}
              </Button>
            </form>
          </CardContent>
          <CardFooter>
               <p className="text-xs text-muted-foreground text-center w-full">
                  © 2025 SafeRoute. All rights reserved.
               </p>
          </CardFooter>
        </Card>
    </div>
  );
}
